import{_ as a,o as t,c as p,j as r,a as b,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"偶像","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/通用及综合类/偶像/偶像.md","filePath":"4.资源分区/6.技艺及称号/通用及综合类/偶像/偶像.md"}'),s={name:"4.资源分区/6.技艺及称号/通用及综合类/偶像/偶像.md"};function o(d,e,l,i,_,c){return t(),p("div",null,[...e[0]||(e[0]=[r("h1",{id:"偶像",tabindex:"-1"},[b("偶像 "),r("a",{class:"header-anchor",href:"#偶像","aria-label":'Permalink to "偶像"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风023元旦版")])])],-1),n('<h1 id="偶像-1" tabindex="-1">偶像 <a class="header-anchor" href="#偶像-1" aria-label="Permalink to &quot;偶像&quot;">​</a></h1><p>偶像<br> 描述：那是永远的向往，如同夜空之中闪耀的繁星。<br> 亦如大地之上绽放的花朵。令每个观众都随之热血沸腾。<br> 如春风般温柔地驱散哀伤。总能让大家喜笑颜开。<br> 正因为想要成为那样美好的人。才会踏入[偶像]的大门——<br> 【出于兴趣原因，主神将学园偶像大师的内容整理成了一套体系，并赋予了该体系将偶像的能力转换为战斗能力的力量，提供给轮回者进行使用。】</p><p>D+500<br> 偶像具有三项属性：声乐，舞蹈，形象，用以衡量作为偶像的素质。<br> 【声乐】数值等同于心智传奇属性之和/3，【舞蹈】数值等同生理传奇属性之和/3，【形象】数值等同互动传奇属性之和/3。<br> 这三项属性会根据你选择的种类而提供对应的效果，因此你在购买该称号时必须从以下三项之一进行选择，作为自己的偶像育成方向。<br> ————<br> 【逻辑】<br> 选择逻辑将获得一种新建攻击方式，使用风度+表达：歌唱+辅助专业：乐理学（学识）进行检定，造成精神伤害。<br> 【逻辑】是以好印象，与干劲来进行育成的方式，你在表达相关检定上获得等同【声乐*2】-1点修行加值。<br> ————<br> 【感性】：选择感性将获得一种新建攻击方式，使用风度+表达：舞蹈+辅助专业：节奏感（专注）进行检定，造成精神伤害。<br> 【感性】是以集中，与好调来育成的方式，你在表达相关检定上获得等同【舞蹈*2】-1点修行加值。<br> ——<br> 非凡：选择非凡将获得一种新建攻击方式，使用风度+表达：演绎+辅助专业：心理学（学识）进行检定，造成精神伤害。<br> 【非凡】是以全力，坚决，温存来育成的方式，你在表达相关检定上获得等同【形象*2】-1点修行加值。<br> ——<br> 虽说如此，即使是育成风格不同也能购买下属的所有技能，与专属物品。<br> ——————————<br> 【专属词条】<br> 元气X：具有元气X的单位，等同具有X点额外的生命值上限。与通常获得生命上限不同，获得这些生命值上限时，不会获得对应的完好与韧性生命值。通常而言，元气带来的生命上限不会受到恢复能力影响，但你也可以使用自身具有的恢复能力来恢复元气带来的生命上限。当元气状态消除以后，对应的生命上限会被移除，处于该生命槽内的严重生命与韧性值也一并被移除。（简单来说，推荐将元气作为一个额外的血槽进行处理）</p><p>干劲X：具有干劲X的单位，等同于具有快速医疗X，每1点干劲/快速医疗则对应12点医疗池点数。</p><p>好调：好调等同【毁灭】特性，在表达相关的攻击检定中生效。你在进行基础规则中不涉及到战斗的表达检定（用于表演）时，好调可以如同进行攻击检定一样正常生效。</p><p>绝好调：绝好调等同【湮灭】特性，其他规则如好调一样处理。当你具有好调状态下，则绝好调除了提供【湮灭】特性，还会提供额外在表达技能上加骰提升1级效果（最高8加骰）。</p><p>集中：每具有1点集中，则你在表达相关检定上获得1个额外附加成功数。</p><p>好印象X：具有好印象X的单位，攻击会对目标造成等同X点不可豁免的类毒素不良点数。该不良点数与毒素不良点数的唯一区别是，好印象带来的不良点数需要使用意志检定豁免，而非强韧检定豁免（精☆神☆中☆毒）。</p><p>全力：处于全力状态下，你进行的表达相关检定出目增加一半计算，这一效果每轮只会生效一次。</p><p>坚决：处于坚决状态下，你进行攻击检定时额外消耗最高内在支线等级*1点意志力，但攻击造成的伤害也会增加一倍。这一效果每轮只会生效一次。</p><p>温存：处于温存状态下，你进行的攻击检定成功数减少一半计算，但受到的伤害也会减少一半计算。这一效果每轮只会生效一次。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',13)])])}const m=a(s,[["render",o]]);export{f as __pageData,m as default};
